export class PersistentVector<T> {
  private count: number;
  private shift: number;
  private root: Node<T> | null;

  private constructor(count: number, shift: number, root: Node<T> | null) {
    this.count = count;
    this.shift = shift;
    this.root = root;
  }

  static empty<T>(): PersistentVector<T> {
    return new PersistentVector<T>(0, -1, null);
  }

  get size(): number {
    return this.count;
  }

  get(i: number): T {
    if (i < 0 || i >= this.count) {
      throw new Error('Index out of bounds');
    }
    return this.getNode(this.root!, this.shift, i);
  }

  private getNode(node: Node<T> | null, level: number, index: number): T {
    if (level < 0) {
      if (node === null) throw new Error('Unexpected null node');
      // leaf node – value stored in `val`
      return node.val!;
    }
    const bit = (index >>> level) & 1;
    const child = bit === 0 ? node?.left : node?.right;
    if (child === null) throw new Error('Unexpected null node');
    return this.getNode(child, level - 1, index);
  }

  push(value: T): PersistentVector<T> {
    const newCount = this.count + 1;
    const newShift = newCount > 0 ? 31 - Math.clz32(newCount - 1) : -1;
    let newRoot: Node<T> | null = this.root;
    if (this.root === null) {
      newRoot = new Node<T>(value, null, null);
    } else {
      if (newShift > this.shift) {
        // need to add a new level
        const oldRoot = this.root;
        const rightSubtree = this.insertIntoEmpty(newShift - 1, 0, value);
        newRoot = new Node<T>(null, oldRoot, rightSubtree);
      } else {
        newRoot = this.insert(this.root, this.shift, this.count, value);
      }
    }
    return new PersistentVector<T>(newCount, newShift, newRoot);
  }

  private insert(node: Node<T> | null, level: number, index: number, value: T): Node<T> {
    if (level < 0) {
      return new Node<T>(value, null, null);
    }
    const bit = (index >>> level) & 1;
    const left = node?.left ?? null;
    const right = node?.right ?? null;
    if (bit === 0) {
      const newLeft = this.insert(left, level - 1, index, value);
      return new Node<T>(null, newLeft, right);
    } else {
      const newRight = this.insert(right, level - 1, index, value);
      return new Node<T>(null, left, newRight);
    }
  }

  private insertIntoEmpty(level: number, index: number, value: T): Node<T> {
    if (level < 0) {
      return new Node<T>(value, null, null);
    }
    const bit = (index >>> level) & 1;
    if (bit === 0) {
      const left = this.insertIntoEmpty(level - 1, index, value);
      return new Node<T>(null, left, null);
    } else {
      const right = this.insertIntoEmpty(level - 1, index, value);
      return new Node<T>(null, null, right);
    }
  }
}

class Node<T> {
  val: T | null;
  left: Node<T> | null;
  right: Node<T> | null;
  constructor(val: T | null = null, left: Node<T> | null = null, right: Node<T> | null = null) {
    this.val = val;
    this.left = left;
    this.right = right;
  }
}

export type Json =
  | null
  | boolean
  | number
  | string
  | Json[]
  | { [key: string]: Json };

class Parser {
  private readonly s: string;
  private i = 0;

  constructor(s: string) {
    this.s = s;
  }

  private peek(): string {
    return this.i < this.s.length ? this.s[this.i] : '';
  }

  private eatWhitespace(): void {
    while (/\s/.test(this.peek())) {
      this.i++;
    }
  }

  private expect(ch: string): void {
    this.eatWhitespace();
    if (this.peek() !== ch) {
      throw new Error(`Expected '${ch}' at position ${this.i}`);
    }
    this.i++;
  }

  parse(): Json {
    const value = this.parseValue();
    this.eatWhitespace();
    if (this.i !== this.s.length) {
      throw new Error(`Trailing garbage after JSON value at position ${this.i}`);
    }
    return value;
  }

  private parseValue(): Json {
    this.eatWhitespace();
    const c = this.peek();
    switch (c) {
      case '{':
        return this.parseObject();
      case '[':
        return this.parseArray();
      case '"':
        return this.parseString();
      case 't':
      case 'f':
        return this.parseBool();
      case 'n':
        return this.parseNull();
      default:
        if (/[-\d]/.test(c)) {
          return this.parseNumber();
        }
        throw new Error(`Unexpected character '${c}' at position ${this.i}`);
    }
  }

  private parseObject(): Json {
    this.expect('{');
    this.eatWhitespace();
    if (this.peek() === '}') {
      this.i++;
      return {};
    }
    const obj: { [key: string]: Json } = {};
    while (true) {
      this.eatWhitespace();
      const key = this.parseString();
      if (typeof key !== 'string') {
        throw new Error(`Object key must be a string at position ${this.i}`);
      }
      this.eatWhitespace();
      this.expect(':');
      this.eatWhitespace();
      const value = this.parseValue();
      obj[key] = value;
      this.eatWhitespace();
      const ch = this.peek();
      if (ch === ',') {
        this.i++; // consume comma
        this.eatWhitespace();
        if (this.peek() === '}') {
          throw new Error(`Trailing comma in object at position ${this.i - 1}`);
        }
        continue;
      } else if (ch === '}') {
        this.i++;
        break;
      } else {
        throw new Error(`Expected ',' or '}}' in object at position ${this.i}`);
      }
    }
    return obj;
  }

  private parseArray(): Json {
    this.expect('[');
    this.eatWhitespace();
    if (this.peek() === ']') {
      this.i++;
      return [];
    }
    const arr: Json[] = [];
    while (true) {
      this.eatWhitespace();
      const value = this.parseValue();
      arr.push(value);
      this.eatWhitespace();
      const ch = this.peek();
      if (ch === ',') {
        this.i++; // consume comma
        this.eatWhitespace();
        if (this.peek() === ']') {
          throw new Error(`Trailing comma in array at position ${this.i - 1}`);
        }
        continue;
      } else if (ch === ']') {
        this.i++;
        break;
      } else {
        throw new Error(`Expected ',' or ']' in array at position ${this.i}`);
      }
    }
    return arr;
  }

  private parseString(): string {
    this.expect('"');
